:root {
  --background: oklch(0.985 0.003 150);
  --foreground: oklch(0.145 0.006 150);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.145 0.006 150);
  --popover: oklch(1 0 0);
  --popover-foreground: oklch(0.145 0.006 150);
  --primary: oklch(0.480 0.114 128);
  --primary-foreground: oklch(0.985 0.003 150);
  --secondary: oklch(0.970 0.004 150);
  --secondary-foreground: oklch(0.205 0.008 150);
  --muted: oklch(0.970 0.004 150);
  --muted-foreground: oklch(0.556 0.012 150);
  --accent: oklch(0.970 0.004 150);
  --accent-foreground: oklch(0.205 0.008 150);
  --destructive: oklch(0.577 0.215 27);
  --destructive-foreground: oklch(0.985 0.003 150);
  --success: oklch(0.700 0.150 162);
  --success-foreground: oklch(0.145 0.006 150);
  --warning: oklch(0.769 0.160 70);
  --warning-foreground: oklch(0.145 0.006 150);
  --border: oklch(0.922 0.006 150);
  --input: oklch(0.922 0.006 150);
  --ring: oklch(0.480 0.114 128);
  --radius: 0.5rem;
}

.dark {
