  --foreground: oklch(0.985 0.003 150);
  --card: oklch(0.205 0.008 150);
  --card-foreground: oklch(0.985 0.003 150);
  --popover: oklch(0.205 0.008 150);
  --popover-foreground: oklch(0.985 0.003 150);
  --primary: oklch(0.785 0.188 128);
  --primary-foreground: oklch(0.145 0.006 150);
  --secondary: oklch(0.269 0.010 150);
  --secondary-foreground: oklch(0.985 0.003 150);
  --muted: oklch(0.269 0.010 150);
  --muted-foreground: oklch(0.708 0.010 150);
  --accent: oklch(0.269 0.010 150);
  --accent-foreground: oklch(0.985 0.003 150);
  --destructive: oklch(0.577 0.215 27);
  --destructive-foreground: oklch(0.985 0.003 150);
  --success: oklch(0.700 0.150 162);
  --success-foreground: oklch(0.145 0.006 150);
  --warning: oklch(0.828 0.155 80);
  --warning-foreground: oklch(0.145 0.006 150);
  --border: oklch(0.269 0.010 150);
  --input: oklch(0.269 0.010 150);
  --ring: oklch(0.785 0.188 128);
}

