@theme {
  --font-sans: "Hanken Grotesk", "Pretendard Variable", Pretendard, ui-sans-serif, system-ui, -apple-system, sans-serif;
  --font-mono: "IBM Plex Mono", "Pretendard Variable", Pretendard, ui-monospace, SFMono-Regular, Menlo, monospace;
  --font-display: "Hanken Grotesk", "Pretendard Variable", Pretendard, ui-sans-serif, system-ui, sans-serif;

  /* type roles */
  --text-display-2xl: 4.5rem;
  --text-display-2xl--line-height: 1.02;
  --text-display-2xl--letter-spacing: -0.022em;
  --text-display-2xl--font-weight: 800;
  --text-display-xl: 3.5rem;
  --text-display-xl--line-height: 1.05;
  --text-display-xl--letter-spacing: -0.02em;
  --text-display-xl--font-weight: 800;
  --text-display-lg: 2.75rem;
  --text-display-lg--line-height: 1.08;
  --text-display-lg--letter-spacing: -0.018em;
  --text-display-lg--font-weight: 800;
  --text-display-md: 2rem;
  --text-display-md--line-height: 1.15;
  --text-display-md--letter-spacing: -0.012em;
  --text-display-md--font-weight: 700;
  --text-display-sm: 1.5rem;
  --text-display-sm--line-height: 1.25;
  --text-display-sm--letter-spacing: -0.01em;
  --text-display-sm--font-weight: 700;
  --text-h1: 1.875rem;
  --text-h1--line-height: 1.2;
  --text-h1--letter-spacing: -0.014em;
  --text-h1--font-weight: 700;
  --text-h2: 1.5rem;
  --text-h2--line-height: 1.25;
  --text-h2--letter-spacing: -0.01em;
  --text-h2--font-weight: 700;
  --text-h3: 1.25rem;
  --text-h3--line-height: 1.3;
  --text-h3--letter-spacing: -0.008em;
  --text-h3--font-weight: 600;
  --text-h4: 1.125rem;
  --text-h4--line-height: 1.4;
  --text-h4--font-weight: 600;
  --text-h5: 1rem;
  --text-h5--line-height: 1.45;
  --text-h5--font-weight: 600;
  --text-h6: 0.875rem;
  --text-h6--line-height: 1.45;
  --text-h6--font-weight: 600;
  --text-body-lg: 1.125rem;
  --text-body-lg--line-height: 1.6;
  --text-body-lg--font-weight: 400;
  --text-body: 1rem;
  --text-body--line-height: 1.6;
  --text-body--font-weight: 400;
  --text-body-sm: 0.875rem;
  --text-body-sm--line-height: 1.55;
  --text-body-sm--font-weight: 400;
  --text-label: 0.875rem;
  --text-label--line-height: 1.4;
  --text-label--font-weight: 500;
  --text-caption: 0.75rem;
  --text-caption--line-height: 1.4;
  --text-caption--font-weight: 400;
  --text-2xs: 0.625rem;
  --text-2xs--line-height: 1.4;
  --text-2xs--font-weight: 400;
  --text-code: 0.875rem;
  --text-code--line-height: 1.5;
  --text-code--font-weight: 400;
  --text-overline: 0.6875rem;
  --text-overline--line-height: 1.4;
  --text-overline--letter-spacing: 0.08em;
  --text-overline--font-weight: 600;

  /* motion — enter = ease-out, exit = ease-in */
  --ease-out: cubic-bezier(0.05, 0.7, 0.1, 1);
  --ease-in: cubic-bezier(0.3, 0, 0.8, 0.15);
  --ease-in-out: cubic-bezier(0.2, 0, 0, 1);
  --ease-brand: cubic-bezier(0.22, 1, 0.36, 1);
  --duration-fast: 120ms;
  --duration-base: 180ms;
  --duration-slow: 240ms;
  --duration-slower: 320ms;

  --shadow-xs: 0 1px 2px -1px rgb(20 20 20 / 0.08);
  --shadow-sm: 0 1px 3px 0 rgb(20 20 20 / 0.1), 0 1px 2px -1px rgb(20 20 20 / 0.1);
  --shadow-md: 0 4px 12px -2px rgb(20 20 20 / 0.12);
  --shadow-lg: 0 12px 32px -8px rgb(20 20 20 / 0.18);
  --shadow-card: 0 1px 2px -1px rgb(20 20 20 / 0.1), 0 10px 28px -14px rgb(20 20 20 / 0.18);

  /* data-viz categorical palette (shared across expressions, distinct + legible on light & dark) */
  --color-chart-1: oklch(0.700 0.150 128);
  --color-chart-2: oklch(0.680 0.160 40);
  --color-chart-3: oklch(0.620 0.150 250);
  --color-chart-4: oklch(0.800 0.150 75);
  --color-chart-5: oklch(0.700 0.130 175);
  --color-chart-6: oklch(0.600 0.160 300);
}

@theme inline {
  --color-background: var(--background);
  --color-foreground: var(--foreground);
  --color-card: var(--card);
  --color-card-foreground: var(--card-foreground);
  --color-popover: var(--popover);
  --color-popover-foreground: var(--popover-foreground);
  --color-primary: var(--primary);
  --color-primary-foreground: var(--primary-foreground);
  --color-secondary: var(--secondary);
  --color-secondary-foreground: var(--secondary-foreground);
  --color-muted: var(--muted);
  --color-muted-foreground: var(--muted-foreground);
  --color-accent: var(--accent);
  --color-accent-foreground: var(--accent-foreground);
  --color-destructive: var(--destructive);
  --color-destructive-foreground: var(--destructive-foreground);
  --color-success: var(--success);
  --color-success-foreground: var(--success-foreground);
  --color-warning: var(--warning);
  --color-warning-foreground: var(--warning-foreground);
  --color-border: var(--border);
  --color-input: var(--input);
  --color-ring: var(--ring);

  --radius-sm: calc(var(--radius) - 2px);
  --radius-md: calc(var(--radius) - 1px);
  --radius-lg: var(--radius);
  --radius-xl: calc(var(--radius) + 4px);
}
